function sevColor(sev) {
  return { high: C.red, med: C.orange, low: C.textDim }[sev] || C.textDim;
}

sevBg:
function sevBg(sev) {
  return { high: C.redDim, med: C.orangeDim, low: '#1e1e1e' }[sev] || '#1e1e1e';
}

