function App() {
  const { TweaksPanel, TweakSection, TweakRadio, TweakToggle, useTweaks } = window;

  const [tweaks, setTweak] = useTweaks(/*EDITMODE-BEGIN*/{
    "view": "results",
    "sidebarCollapsed": true,
    "iocOpen": true,
    "lang": "py"
  }/*EDITMODE-END*/);

  const { view, sidebarCollapsed, iocOpen, lang } = tweaks;
  // lt = null on upload (lang unknown), set after detection
  const lt = view === 'empty' ? getLangTheme(null) : getLangTheme(lang);
  if (typeof window !== 'undefined') { window.__lth = lt; window.__lang = view==='empty' ? null : lang; }
  const [activeSession, setActiveSession] = useState(1);

  return (
    <div style={{ display:'flex', flexDirection:'column', height:'100%', overflow:'hidden',
      background: C.bg }}>
      <Header view={view} onNewAnalysis={() => setTweak('view','empty')} lt={lt} />
      <div style={{ flex:1, display:'flex', overflow:'hidden' }}>
        <Sidebar
          collapsed={sidebarCollapsed}
          onToggle={() => setTweak('sidebarCollapsed', !sidebarCollapsed)}
          activeSession={activeSession}
          setActiveSession={setActiveSession}
          lang={lang}
          lt={lt}
        />
        <div style={{ flex:1, display:'flex', overflow:'hidden' }}>
          {view === 'empty'     && <EmptyState lang={lang} />}
          {view === 'analyzing' && <AnalyzingState lang={lang} lt={lt} />}
          {view === 'results'   && <ResultsState iocOpen={iocOpen} setIocOpen={v=>setTweak('iocOpen',v)} lang={lang} lt={lt} />}
        </div>
      </div>
      <Footer view={view} lt={lt} />

      <TweaksPanel>
        <TweakSection label="View">
          <TweakRadio id="view" label="Screen" value={view}
            options={[
              {value:'empty',     label:'Upload'},
              {value:'analyzing', label:'Analyzing'},
              {value:'results',   label:'Results'},
            ]}
            onChange={v=>setTweak('view',v)} />
        </TweakSection>
        <TweakSection label="Language">
          <TweakRadio id="lang" label="File type" value={lang}
            options={[
              {value:'js',  label:'JS'},
              {value:'py',  label:'Python'},
            ]}
            onChange={v=>setTweak('lang',v)} />
        </TweakSection>
        <TweakSection label="Layout">
          <TweakToggle id="sidebarCollapsed" label="Collapse sidebar"
            value={sidebarCollapsed} onChange={v=>setTweak('sidebarCollapsed',v)} />
          {view==='results' && (
            <TweakToggle id="iocOpen" label="IOC panel"
              value={iocOpen} onChange={v=>setTweak('iocOpen',v)} />
          )}
        </TweakSection>
      </TweaksPanel>
    </div>
  );
}
